order by partitiondate desc

select sum(t.partitioncount) as partitionCount from
(select partitioncount from synlte.syndmg_table_all
where tableproject = #{syndmgTableAll.tableProject,jdbcType=VARCHAR}
and tablename = #{syndmgTableAll.tableName,jdbcType=VARCHAR}
and tabletype = #{syndmgTableAll.tableType,jdbcType=VARCHAR}
order by partitiondate desc) t
where rownum <= #{syndmgTableAll.lifeCycle,jdbcType=VARCHAR}

